def countingSort(nums):
    if not nums:
        return nums
    max_val = max(nums)
    count = [0] * (max_val + 1)
    for num in nums:
        count[num] += 1
    result = []
    for i, c in enumerate(count):
        result.extend([i] * c)
    return result

