def radixSort(nums):
    if not nums:
        return nums
    max_val = max(nums)
    exp = 1
    while max_val // exp > 0:
        counting_sort_by_digit(nums, exp)
        exp *= 10
    return nums

def counting_sort_by_digit(nums, exp):
    n = len(nums)
    output = [0] * n
    count = [0] * 10
    for num in nums:
        index = (num // exp) % 10
        count[index] += 1
    for i in range(1, 10):
        count[i] += count[i - 1]
    for i in range(n - 1, -1, -1):
        index = (nums[i] // exp) % 10
        output[count[index] - 1] = nums[i]
        count[index] -= 1
    for i in range(n):
        nums[i] = output[i]

