def bucketSort(nums):
    if not nums:
        return nums
    n = len(nums)
    buckets = [[] for _ in range(n)]
    for num in nums:
        idx = int(num * n)
        buckets[idx].append(num)
    for bucket in buckets:
        bucket.sort()
    result = []
    for bucket in buckets:
        result.extend(bucket)
    return result

